//! BIDS filename parsing
//!
//! This module provides functionality for parsing BIDS filenames and extracting
//! entities according to the BIDS specification.

use std::collections::HashMap;
use regex::Regex;
use once_cell::sync::Lazy;

use crate::error::{BidsError, Result};
use crate::file::BidsFile;

/// Result of parsing a BIDS filename
#[derive(Debug, Clone, PartialEq)]
pub struct ParseResult {
    /// Extracted entities
    pub entities: HashMap<String, String>,
    /// File suffix (e.g., "bold", "events")
    pub suffix: String,
    /// File extension (e.g., "nii.gz", "tsv")
    pub extension: String,
    /// File type/kind (e.g., "func", "anat")
    pub kind: Option<String>,
    /// Modality (e.g., "bold", "T1w")
    pub modality: Option<String>,
}

/// BIDS filename parser
pub struct BidsParser {
    /// Parser specifications
    parsers: Vec<ParserSpec>,
}

/// Parser specification for a specific file type
#[derive(Debug, Clone)]
struct ParserSpec {
    /// File type (e.g., "func", "anat")
    kind: String,
    /// Regex pattern for matching filenames
    pattern: Regex,
    /// Entity keys that this parser extracts
    entity_keys: Vec<String>,
    /// Possible suffixes for this file type
    suffixes: Vec<String>,
    /// Possible extensions for this file type
    extensions: Vec<String>,
}

// Compiled regex patterns for common BIDS entities
static ENTITY_PATTERNS: Lazy<HashMap<&'static str, Regex>> = Lazy::new(|| {
    let mut patterns = HashMap::new();

    // Core entities
    patterns.insert("sub", Regex::new(r"sub-([a-zA-Z0-9]+)").unwrap());
    patterns.insert("ses", Regex::new(r"ses-([a-zA-Z0-9]+)").unwrap());
    patterns.insert("task", Regex::new(r"task-([a-zA-Z0-9]+)").unwrap());
    patterns.insert("run", Regex::new(r"run-([0-9]+)").unwrap());
    patterns.insert("acq", Regex::new(r"acq-([a-zA-Z0-9]+)").unwrap());
    patterns.insert("ce", Regex::new(r"ce-([a-zA-Z0-9]+)").unwrap());
    patterns.insert("dir", Regex::new(r"dir-([a-zA-Z0-9]+)").unwrap());
    patterns.insert("rec", Regex::new(r"rec-([a-zA-Z0-9]+)").unwrap());
    patterns.insert("echo", Regex::new(r"echo-([0-9]+)").unwrap());
    patterns.insert("space", Regex::new(r"space-([a-zA-Z0-9]+)").unwrap());
    patterns.insert("desc", Regex::new(r"desc-([a-zA-Z0-9]+)").unwrap());

    patterns
});

impl BidsParser {
    /// Create a new BIDS parser
    pub fn new() -> Self {
        Self {
            parsers: Self::create_default_parsers(),
        }
    }

    /// Parse a BIDS filename
    pub fn parse(&self, filename: &str) -> Result<ParseResult> {
        for parser in &self.parsers {
            if let Some(result) = self.try_parse_with_spec(filename, parser)? {
                return Ok(result);
            }
        }

        Err(BidsError::parse_error(
            filename,
            "No parser matched the filename",
        ))
    }

    /// Try to parse a filename with a specific parser specification
    fn try_parse_with_spec(&self, filename: &str, spec: &ParserSpec) -> Result<Option<ParseResult>> {
        if !spec.pattern.is_match(filename) {
            return Ok(None);
        }

        let entities = self.extract_entities(filename)?;
        let (suffix, extension) = self.extract_suffix_and_extension(filename)?;

        // Validate that the suffix is acceptable for this parser
        if !spec.suffixes.is_empty() && !spec.suffixes.contains(&suffix) {
            return Ok(None);
        }

        // Validate that the extension is acceptable for this parser
        if !spec.extensions.is_empty() && !spec.extensions.contains(&extension) {
            return Ok(None);
        }

        let modality = self.determine_modality(&suffix, &spec.kind);

        Ok(Some(ParseResult {
            entities,
            suffix,
            extension,
            kind: Some(spec.kind.clone()),
            modality,
        }))
    }

    /// Extract entities from a filename
    fn extract_entities(&self, filename: &str) -> Result<HashMap<String, String>> {
        let mut entities = HashMap::new();

        for (key, pattern) in ENTITY_PATTERNS.iter() {
            if let Some(captures) = pattern.captures(filename) {
                if let Some(value) = captures.get(1) {
                    entities.insert(key.to_string(), value.as_str().to_string());
                }
            }
        }

        Ok(entities)
    }

    /// Extract suffix and extension from a filename
    fn extract_suffix_and_extension(&self, filename: &str) -> Result<(String, String)> {
        // Handle .nii.gz extension specially
        if filename.ends_with(".nii.gz") {
            let without_ext = filename.trim_end_matches(".nii.gz");
            let suffix = self.extract_suffix_from_stem(without_ext);
            return Ok((suffix, "nii.gz".to_string()));
        }

        // Handle other extensions
        if let Some(dot_pos) = filename.rfind('.') {
            let extension = filename[dot_pos + 1..].to_string();
            let stem = &filename[..dot_pos];
            let suffix = self.extract_suffix_from_stem(stem);
            return Ok((suffix, extension));
        }

        Err(BidsError::parse_error(
            filename,
            "Could not determine file extension",
        ))
    }

    /// Extract suffix from the filename stem
    fn extract_suffix_from_stem(&self, stem: &str) -> String {
        // Find the last underscore and take everything after it
        if let Some(underscore_pos) = stem.rfind('_') {
            stem[underscore_pos + 1..].to_string()
        } else {
            stem.to_string()
        }
    }

    /// Determine modality from suffix and kind
    fn determine_modality(&self, suffix: &str, kind: &str) -> Option<String> {
        match (kind, suffix) {
            ("func", "bold") => Some("bold".to_string()),
            ("anat", suffix) if matches!(suffix, "T1w" | "T2w" | "FLAIR" | "PDw") => {
                Some(suffix.to_string())
            }
            ("dwi", "dwi") => Some("dwi".to_string()),
            ("fmap", suffix) if matches!(suffix, "fieldmap" | "magnitude" | "phase") => {
                Some(suffix.to_string())
            }
            _ => None,
        }
    }

    /// Create default parser specifications
    fn create_default_parsers() -> Vec<ParserSpec> {
        vec![
            // Functional MRI
            ParserSpec {
                kind: "func".to_string(),
                pattern: Regex::new(r".*_bold\.nii(\.gz)?$").unwrap(),
                entity_keys: vec!["sub".to_string(), "ses".to_string(), "task".to_string(), "run".to_string()],
                suffixes: vec!["bold".to_string()],
                extensions: vec!["nii.gz".to_string(), "nii".to_string()],
            },
            // Anatomical MRI
            ParserSpec {
                kind: "anat".to_string(),
                pattern: Regex::new(r".*_(T1w|T2w|FLAIR|PDw)\.nii(\.gz)?$").unwrap(),
                entity_keys: vec!["sub".to_string(), "ses".to_string(), "acq".to_string(), "rec".to_string()],
                suffixes: vec!["T1w".to_string(), "T2w".to_string(), "FLAIR".to_string(), "PDw".to_string()],
                extensions: vec!["nii.gz".to_string(), "nii".to_string()],
            },
            // Event files
            ParserSpec {
                kind: "func".to_string(),
                pattern: Regex::new(r".*_events\.tsv$").unwrap(),
                entity_keys: vec!["sub".to_string(), "ses".to_string(), "task".to_string(), "run".to_string()],
                suffixes: vec!["events".to_string()],
                extensions: vec!["tsv".to_string()],
            },
            // Sidecar JSON files
            ParserSpec {
                kind: "func".to_string(),
                pattern: Regex::new(r".*_bold\.json$").unwrap(),
                entity_keys: vec!["sub".to_string(), "ses".to_string(), "task".to_string(), "run".to_string()],
                suffixes: vec!["bold".to_string()],
                extensions: vec!["json".to_string()],
            },
        ]
    }
}

impl Default for BidsParser {
    fn default() -> Self {
        Self::new()
    }
}

/// Parse a BIDS filename using the default parser
pub fn parse_filename(filename: &str) -> Result<ParseResult> {
    let parser = BidsParser::new();
    parser.parse(filename)
}

/// Parse a BIDS filename and create a BidsFile
pub fn parse_to_bids_file(filename: &str, full_path: Option<&str>) -> Result<BidsFile> {
    let parse_result = parse_filename(filename)?;

    let path = full_path.unwrap_or(filename);
    let mut file = BidsFile::new(path);

    // Set entities
    for (key, value) in parse_result.entities {
        file.set_entity(key, value);
    }

    // Set other fields
    file.suffix = parse_result.suffix;
    file.extension = parse_result.extension;
    file.kind = parse_result.kind;
    file.modality = parse_result.modality;

    Ok(file)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_parse_func_filename() {
        let result = parse_filename("sub-01_task-rest_run-01_bold.nii.gz").unwrap();

        assert_eq!(result.entities.get("sub"), Some(&"01".to_string()));
        assert_eq!(result.entities.get("task"), Some(&"rest".to_string()));
        assert_eq!(result.entities.get("run"), Some(&"01".to_string()));
        assert_eq!(result.suffix, "bold");
        assert_eq!(result.extension, "nii.gz");
        assert_eq!(result.kind, Some("func".to_string()));
