//! File discovery and search functionality
//!
//! This module provides tools for discovering and searching BIDS files
//! based on various criteria.

use std::collections::HashMap;
use std::path::PathBuf;

use crate::error::{BidsError, Result};
use crate::file::BidsFile;
use crate::project::BidsProject;

/// Builder for constructing file search queries
#[derive(Debug, Clone)]
pub struct SearchBuilder<'a> {
    /// Reference to the BIDS project
    project: &'a BidsProject,
    /// Entity filters
    filters: HashMap<String, String>,
    /// File suffix filter
    suffix_filter: Option<String>,
    /// File extension filter
    extension_filter: Option<String>,
    /// File kind filter
    kind_filter: Option<String>,
    /// Whether to search in derivatives
    search_derivatives: bool,
    /// Whether to return full paths
    full_paths: bool,
}

impl<'a> SearchBuilder<'a> {
    /// Create a new search builder
    pub fn new(project: &'a BidsProject) -> Self {
        Self {
            project,
            filters: HashMap::new(),
            suffix_filter: None,
            extension_filter: None,
            kind_filter: None,
            search_derivatives: false,
            full_paths: true,
        }
    }

    /// Filter by subject ID
    pub fn subject(mut self, subject: impl Into<String>) -> Self {
        self.filters.insert("sub".to_string(), subject.into());
        self
    }

    /// Filter by session ID
    pub fn session(mut self, session: impl Into<String>) -> Self {
        self.filters.insert("ses".to_string(), session.into());
        self
    }

    /// Filter by task
    pub fn task(mut self, task: impl Into<String>) -> Self {
        self.filters.insert("task".to_string(), task.into());
        self
    }

    /// Filter by run
    pub fn run(mut self, run: impl Into<String>) -> Self {
        self.filters.insert("run".to_string(), run.into());
        self
    }

    /// Filter by acquisition
    pub fn acquisition(mut self, acq: impl Into<String>) -> Self {
        self.filters.insert("acq".to_string(), acq.into());
        self
    }

    /// Filter by space
    pub fn space(mut self, space: impl Into<String>) -> Self {
        self.filters.insert("space".to_string(), space.into());
        self
    }

    /// Filter by description
    pub fn desc(mut self, desc: impl Into<String>) -> Self {
        self.filters.insert("desc".to_string(), desc.into());
        self
    }

    /// Filter by file suffix
    pub fn suffix(mut self, suffix: impl Into<String>) -> Self {
        self.suffix_filter = Some(suffix.into());
        self
    }

    /// Filter by file extension
    pub fn extension(mut self, extension: impl Into<String>) -> Self {
        self.extension_filter = Some(extension.into());
        self
    }

    /// Filter by file kind
    pub fn kind(mut self, kind: impl Into<String>) -> Self {
        self.kind_filter = Some(kind.into());
        self
    }

    /// Search in derivatives directory
    pub fn derivatives(mut self, search_derivatives: bool) -> Self {
        self.search_derivatives = search_derivatives;
        self
    }

    /// Return full paths vs relative paths
    pub fn full_paths(mut self, full_paths: bool) -> Self {
        self.full_paths = full_paths;
        self
    }

    /// Execute the search and return matching files
    pub fn collect(self) -> Result<Vec<BidsFile>> {
        // This is a placeholder implementation
        // In a full implementation, this would:
        // 1. Walk through the appropriate directories
        // 2. Parse filenames
        // 3. Apply filters
        // 4. Return matching files

        // For now, return empty results
        Ok(Vec::new())
    }

    /// Execute the search and return file paths
    pub fn paths(self) -> Result<Vec<PathBuf>> {
        let files = self.collect()?;
        Ok(files.into_iter().map(|f| f.path).collect())
    }

    /// Execute the search and return the first matching file
    pub fn first(self) -> Result<Option<BidsFile>> {
        let mut files = self.collect()?;
        Ok(files.pop())
    }

    /// Count matching files without loading them
    pub fn count(self) -> Result<usize> {
        let files = self.collect()?;
        Ok(files.len())
    }

    /// Check if any files match the criteria
    pub fn exists(self) -> Result<bool> {
        Ok(self.count()? > 0)
    }
}

/// Search for files in a BIDS project
pub fn search_files(
    project: &BidsProject,
    filters: &HashMap<String, String>,
) -> Result<Vec<BidsFile>> {
    let mut builder = SearchBuilder::new(project);

    for (key, value) in filters {
        builder.filters.insert(key.clone(), value.clone());
    }

    builder.collect()
}

/// Find functional scans matching criteria
pub fn find_func_scans(
    project: &BidsProject,
    subject: Option<&str>,
    task: Option<&str>,
    run: Option<&str>,
) -> Result<Vec<BidsFile>> {
    let mut builder = SearchBuilder::new(project).kind("bold");

    if let Some(sub) = subject {
        builder = builder.subject(sub);
    }

    if let Some(task) = task {
        builder = builder.task(task);
    }

    if let Some(run) = run {
        builder = builder.run(run);
    }

    builder.collect()
}

/// Find event files matching criteria
pub fn find_event_files(
    project: &BidsProject,
    subject: Option<&str>,
    task: Option<&str>,
    run: Option<&str>,
) -> Result<Vec<BidsFile>> {
    let mut builder = SearchBuilder::new(project).suffix("events");

    if let Some(sub) = subject {
        builder = builder.subject(sub);
    }

    if let Some(task) = task {
        builder = builder.task(task);
    }

    if let Some(run) = run {
        builder = builder.run(run);
    }

    builder.collect()
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;
    use std::fs;

    fn create_test_project() -> Result<(TempDir, BidsProject)> {
        let temp_dir = TempDir::new()?;
        let root = temp_dir.path();

        // Create minimal BIDS structure
        let participants_content = "participant_id\nsub-01\nsub-02\n";
        fs::write(root.join("participants.tsv"), participants_content)?;

        let dataset_description = serde_json::json!({
            "Name": "Test Dataset",
            "BIDSVersion": "1.8.0"
        });
        fs::write(
            root.join("dataset_description.json"),
            serde_json::to_string_pretty(&dataset_description)?,
        )?;

        let project = BidsProject::new(root)?;
        Ok((temp_dir, project))
    }

    #[test]
    fn test_search_builder_creation() -> Result<()> {
        let (_temp_dir, project) = create_test_project()?;
        let builder = SearchBuilder::new(&project);

        assert!(builder.filters.is_empty());
        assert!(builder.suffix_filter.is_none());
        assert!(!builder.search_derivatives);
        assert!(builder.full_paths);

        Ok(())
    }

    #[test]
    fn test_search_builder_filters() -> Result<()> {
        let (_temp_dir, project) = create_test_project()?;
        let builder = SearchBuilder::new(&project)
            .subject("01")
            .task("rest")
